import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import SearchBar from "./SearchBar";
import "./Navbar.css"; // 👉 NEW CSS FILE

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const navigate = useNavigate();

  return (
    <nav className="navbar">
      <div className="nav-container">

        {/* LOGO */}
        <Link to="/" className="logo">
          📚 <span>Study Portal</span>
        </Link>

        {/* MOBILE MENU BUTTON */}
        <button
          className="menu-btn"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
        >
          {isMenuOpen ? "✕" : "☰"}
        </button>

        {/* NAV LINKS */}
        <div className={`nav-links ${isMenuOpen ? "active" : ""}`}>

          <Link to="/" className="nav-link">
            Home
          </Link>

          {/* Courses Dropdown */}
          <div className="dropdown">
            <span className="nav-link">Courses ▼</span>

            <div className="dropdown-content">
              <Link to="/course/1">🎓 B.Tech</Link>
              <Link to="/course/2">📱 BCA</Link>
              <Link to="/course/3">📊 BBA</Link>
              <Link to="/course/4">💼 MBA</Link>
              <Link to="/course/5">💻 MCA</Link>
            </div>
          </div>

          <Link to="/upload" className="nav-link">Upload</Link>
          <Link to="/about" className="nav-link">About</Link>

          {/* SEARCHBAR */}
          <SearchBar />

          {/* AUTH BUTTONS */}
          <div className="auth-buttons">
            <button onClick={() => navigate("/login")} className="login-btn">
              Login
            </button>
            <button
              onClick={() => navigate("/register")}
              className="register-btn"
            >
              Register
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
